const raw  = $json;
const body = raw.body  ?? raw;
const data = body.data ?? body;

if (!data || typeof data !== 'object') {
  throw new Error('Unexpected webhook payload. Got: ' + JSON.stringify(raw).substring(0, 300));
}

const meta = {
  formSubmissionId: data._id        ?? null,
  contentRef:       data.contentRef ?? null,
  submittedById:    data.updatedBy  ?? null,
  submittedAt:      data.updatedAt  ?? null,
};

function normalize(field) {
  const el = field.element;
  const v  = field.value;
  let value;
  if (v == null) {
    value = null;
  } else if (el === 'NodeSelector') {
    value = typeof v === 'object' && !Array.isArray(v)
      ? { id: v.value, label: v.label ?? null, descendants: v.descendants ?? [] }
      : v;
  } else if (['RadioButtons', 'CheckboxGroup', 'Dropdown'].includes(el)) {
    value = Array.isArray(v) ? v.map(o => o.value || o.text?.nl || o.key) : v;
  } else if (el === 'Stars' || el === 'Smileys') {
    value = typeof v === 'number' ? v : parseInt(v, 10) || v;
  } else {
    value = v;
  }
  return { ffId: field.ffId ?? null, element: el ?? 'Unknown', value, raw: v };
}

const fields = (data.values ?? []).map(normalize);
const byFfId = Object.fromEntries(fields.filter(f => f.ffId).map(f => [f.ffId, f]));

return [{ json: { ...meta, fields, byFfId } }];

const formData = $('Extract Form Data').first().json;
const userData = $input.first().json;

// Strategy 1: first NodeSelector in form fields
const ns = formData.fields.find(f => f.element === 'NodeSelector');
let orgNodeId = null;
let resolvedFrom = null;

if (ns && ns.raw) {
  orgNodeId = typeof ns.raw === 'object' ? ns.raw.value : String(ns.raw);
  resolvedFrom = 'NodeSelector';
}

// Strategy 2: submitter's first orgunit
if (!orgNodeId && userData.orgunits && userData.orgunits.length > 0) {
  const first = userData.orgunits[0];
  orgNodeId = typeof first === 'string' ? first : (first._id || first.id || String(first));
  resolvedFrom = 'userProfile';
}

if (!orgNodeId) {
  throw new Error(
    'No org node found. No NodeSelector in form and user ' +
    (userData._id || 'unknown') + ' has no orgunits.'
  );
}

return [{ json: { orgNodeId, resolvedFrom } }];

const formData = $('Extract Form Data').first().json;
const schema   = $('Get Form Schema').first().json;

const schemaFields = schema.form?.fields || schema.template?.form?.fields || [];

// Lookup by ffId for precise matching
const schemaByFfId = {};
schemaFields.forEach(sf => {
  const key = sf.ffId || sf.field_name;
  if (key) schemaByFfId[key] = sf;
});

// Fallback: sequential index over non-decorator fields
const inputFields = schemaFields.filter(
  sf => !['Paragraph', 'Header', 'Section'].includes(sf.element)
);

const rawTitle  = schema.title || schema.template?.title || {};
const formTitle = Object.values(rawTitle)[0] || 'Form submission';

const fieldLines = formData.fields.map((field, i) => {
  const sf    = (field.ffId && schemaByFfId[field.ffId]) || inputFields[i];
  const label = sf?.label ? Object.values(sf.label)[0] : `Field ${i + 1}`;
  const el    = field.element;
  let val;
  if (field.value == null) {
    val = '(not filled)';
  } else if (el === 'NodeSelector' && typeof field.value === 'object') {
    val = field.value.label || field.value.id;
  } else if (Array.isArray(field.value)) {
    val = field.value.join(', ');
  } else {
    val = String(field.value);
  }
  return `- ${label} [${el}]: ${val}`;
}).join('\n');

const prompt = `You are designing a follow-up task in Keephub for a retail manager.\n\nA \"${formTitle}\" was just submitted:\n${fieldLines}\n\nDesign ONE actionable task the manager must complete in response.\n\nLanguage rules:\n- Detect the language from the data (most likely \"nl\" or \"en\")\n- Use the detected BCP-47 code as key in every title/label object\n- All your text must be in that language\n\nTask design rules:\n1. Title must reference specifics from this submission (name, store, form type) — never generic\n2. First field must be a Paragraph briefly explaining what the manager must do\n3. Only add fields the manager needs to fill in — never repeat submitted data\n4. Labels must be specific and actionable (not \"Notes\" but \"Reason for approval\")\n5. Match field types to content: RadioButtons for yes/no, DatePicker for dates, TextArea for justifications\n6. 3–6 fields maximum\n\nAvailable elements (exact strings):\n- \"TextInput\" \"TextArea\" \"NumberInput\" \"DatePicker\"\n- \"RadioButtons\" \"Checkboxes\" \"Dropdown\" (these require options array)\n- \"Stars\" \"Smileys\" \"Paragraph\" (Paragraph = static text, content goes in label)\n\nReturn ONLY valid JSON, no markdown fences:\n{\n  \"title\": { \"<lang>\": \"...\" },\n  \"introText\": { \"<lang>\": \"One sentence context for the manager.\" },\n  \"fields\": [\n    { \"element\": \"Paragraph\", \"label\": { \"<lang>\": \"...\" } },\n    { \"element\": \"RadioButtons\", \"label\": { \"<lang>\": \"...\" }, \"required\": true, \"options\": [{ \"text\": { \"<lang>\": \"A\" } }, { \"text\": { \"<lang>\": \"B\" } }] }\n  ]\n}`;

return [{ json: { prompt } }];

const cfg      = $('⚙️ Config').first().json;
const formData = $('Extract Form Data').first().json;

// --- Parse AI response ---
// Long extraction chain handles different OpenAI node output formats across versions
// (structured output, message.content array, legacy choices[], raw text)
const aiContent = $input.first().json;
const aiRaw =
  aiContent?.output?.[0]?.content?.find(b => b.type === 'output_text')?.text ||
  aiContent?.output?.[0]?.content?.[0]?.text ||
  (Array.isArray(aiContent?.message?.content)
    ? aiContent.message.content.find(b => b.type === 'text')?.text
    : aiContent?.message?.content) ||
  aiContent?.choices?.[0]?.message?.content ||
  aiContent?.text ||
  null;

if (!aiRaw) throw new Error('AI returned no content: ' + JSON.stringify(aiContent).substring(0, 300));

let aiTask;
try {
  aiTask = JSON.parse(aiRaw.replace(/```json|```/g, '').trim());
} catch (e) {
  throw new Error('AI returned invalid JSON: ' + String(aiRaw).substring(0, 300));
}
if (Array.isArray(aiTask)) {
  aiTask = { title: { en: 'Review submission' }, introText: { en: 'Please review.' }, fields: aiTask };
}
if (!aiTask.title || typeof aiTask.title !== 'object') throw new Error('Missing title');
if (!aiTask.introText || typeof aiTask.introText !== 'object') throw new Error('Missing introText');
if (!Array.isArray(aiTask.fields) || !aiTask.fields.length) throw new Error('Missing fields');

// --- Config validation ---
const OBJECT_ID = /^[a-f0-9]{24}$/i;
const dueDays    = cfg.taskDueDaysFromNow ?? 1;
if (typeof dueDays !== 'number' || dueDays < 0) {
  throw new Error(`taskDueDaysFromNow must be >= 0, got: ${dueDays}`);
}

// Validate groupId — invalid non-empty strings will broadcast org-wide
let groupId = null;
if (cfg.groupId && typeof cfg.groupId === 'string' && cfg.groupId.trim()) {
  if (OBJECT_ID.test(cfg.groupId)) {
    groupId = cfg.groupId;
  } else {
    throw new Error(
      `Invalid groupId "${cfg.groupId}" — must be a 24-char hex ObjectID. ` +
      `Without a valid groupId, task targets EVERYONE on the node. ` +
      `Check Keephub admin for the correct group ID.`
    );
  }
}

const webhookUrl = cfg.workflow2WebhookUrl || '';

const contentRef       = formData.contentRef       || '';
const formSubmissionId = formData.formSubmissionId || '';

// --- Org target (from parent/root path) ---
// Merge both paths: try Extract Parent Target first, fall back to Extract Root Target
let target;
try {
  target = $('Extract Parent Target').first().json;
  if (!target || !target.targetNodeId) throw new Error('No targetNodeId in parent');
} catch {
  try {
    target = $('Extract Root Target').first().json;
    if (!target || !target.targetNodeId) throw new Error('No targetNodeId in root');
  } catch (err2) {
    throw new Error(
      'No target node resolved from either parent or root path. ' +
      'Check Get Parent Node / Get Root Node outputs.'
    );
  }
}
const targetId          = target.targetNodeId;
const targetDescendants = target.descendants || [];
const resolvedGroups    = groupId ? [groupId] : [];

if (!targetId) throw new Error('No target node resolved');

// --- Dates (n8n global DateTime = Luxon) ---
const now       = DateTime.now();
const startDate = now.startOf('day').plus({ minutes: 1 });
const dueDate   = now.plus({ days: dueDays }).endOf('day');
const timezone  = now.zoneName;

// --- Helpers ---
// Generate cryptographically strong ObjectID-like strings
function objectId() {
  const buf = crypto.randomBytes(12);
  return buf.toString('hex');
}

const langs = Object.keys(aiTask.title);
const linkLabels = { nl: 'Bekijk de originele inzending', en: 'View the original submission' };

// --- Intro paragraph with link to submission (URL-encoded) ---
const encodedContentRef = encodeURIComponent(contentRef);
const encodedSubmissionId = encodeURIComponent(formSubmissionId);
const introField = {
  id: objectId(), required: false, element: 'Paragraph',
  static: true, bold: false, italic: false, content: '',
  text: Object.fromEntries(langs.map(lang => [
    lang,
    `<p>${aiTask.introText[lang] || ''} <a href=\"/system/content/${encodedContentRef}/formValueId/${encodedSubmissionId}/view\">${linkLabels[lang] || linkLabels.en}</a>.</p>`
  ])),
  type: '', editingFieldId: '', sectionIndex: null, insideSection: null, orderIndex: 0
};

// --- Build dynamic fields with validation ---
const OPTION_ELEMENTS = ['RadioButtons', 'Checkboxes', 'Dropdown'];

const dynamicFields = aiTask.fields
  .filter(f => f.element && (f.label || f.element === 'Paragraph'))
  .map((f, index) => {
    const id  = objectId();
    const isParagraph = f.element === 'Paragraph';

    // Validate Paragraph has label
    if (isParagraph && (!f.label || typeof f.label !== 'object' || !Object.keys(f.label).length)) {
      throw new Error(`AI returned Paragraph field at index ${index} with no label. All Paragraph fields must have a label object.`);
    }

    const field = {
      id, required: f.required ?? false, element: f.element,
      type: '', editingFieldId: '', sectionIndex: null, insideSection: null,
      orderIndex: index + 1
    };
    if (isParagraph) {
      Object.assign(field, { static: true, bold: false, italic: false, content: '', text: f.label });
    } else {
      field.field_name = id;
      field.label = f.label;
    }
    if (OPTION_ELEMENTS.includes(f.element)) {
      // Validate options array
      if (!Array.isArray(f.options) || !f.options.length) {
        throw new Error(
          `AI returned ${f.element} field at index ${index} with no options array. ` +
          `${f.element} requires at least one option.`
        );
      }
      // Validate each option has text object
      f.options.forEach((opt, i) => {
        if (!opt.text || typeof opt.text !== 'object' || !Object.keys(opt.text).length) {
          throw new Error(
            `AI returned ${f.element} field at index ${index}, option ${i} with malformed text. ` +
            `Expected {"<lang>": "..."}, got: ${JSON.stringify(opt.text)}`
          );
        }
      });
      field.shouldTranslate = false;
      field.hiddenValues = false;
      field.options = f.options.map(opt => ({
        value: '', text: opt.text, showRemark: false, remark: '', key: objectId()
      }));
      if (f.element !== 'Dropdown') field.hiddenRemarks = false;
    }
    if (f.element === 'TextArea') field.multiline = true;
    if (f.element === 'NumberInput') { if (f.min != null) field.min = f.min; if (f.max != null) field.max = f.max; }
    if (f.element === 'DatePicker') {
      Object.assign(field, {
        readOnly: false, defaultToday: false, dateFormat: 'MM/dd/yyyy',
        timeFormat: 'hh:mm aa', showTimeSelect: false, showTimeSelectOnly: false
      });
    }
    return field;
  });

// --- Final payload (single task, no repeat) ---
return [{ json: {
  sendPushNotification:  true,
  orgchartSelection:     { include: [targetId], exclude: targetDescendants },
  parentRef:             null,
  orgchartAttrSelection: [],
  groups:                resolvedGroups,
  type:                  'single',
  template: {
    originLanguage:  langs[0],
    startDate:       startDate.toISO(),
    dueDate:         dueDate.toISO(),
    completionType:  'group',
    timezone,
    endGroup:        'never',
    title:           aiTask.title,
    attachments:     Object.fromEntries(langs.map(l => [l, []])),
    relatedTags:     [],
    form:            { active: true, fields: [introField, ...dynamicFields] },
    hookurls:        webhookUrl ? [{ url: webhookUrl, active: true }] : [],
    highlighted:     false,
    templateEndDate: null
  }
}}];

const result = $input.first().json;
const parent = result.parent || result;
if (!parent._id) throw new Error('Parent node has no _id');
return [{ json: { targetNodeId: parent._id, descendants: parent.descendants || [], isRoot: false } }];

// Get ancestors returns array from current node up to root
// The last item is the actual organizational root
const response = $input.first().json;
let root;
if (Array.isArray(response)) {
  // If ancestors array is returned, take the last (topmost) ancestor as root
  root = response.length > 0 ? response[response.length - 1] : null;
} else if (response.ancestors && Array.isArray(response.ancestors)) {
  root = response.ancestors.length > 0 ? response.ancestors[response.ancestors.length - 1] : null;
} else {
  root = response;
}
if (!root || (!root._id && !root.id)) {
  throw new Error('No root node found in ancestors response');
}
return [{ json: { targetNodeId: root._id || root.id, descendants: root.descendants || [], isRoot: true } }];
